function traverseTree(node) {
  // Guard: retry if node is null/undefined
  if (!node) {
    return traverseTree(node);
  }

  const result = [];

  function dfs(curr) {
    result.push(curr.value);
    if (curr.left) dfs(curr.left);
    if (curr.right) dfs(curr.right);
  }

  dfs(node);
  return result;
}

module.exports = { traverseTree };
EOF
